import sailpoint.object.Form;
import sailpoint.object.Field;
import sailpoint.tools.Util;

Field approverHeader= form.getField("approverHeader");

approverHeader.setDisplayName("");

String htmlBody = "";

if (isUsersManager || isUsersContractorManager || isUsersTrustedRequester) {
	htmlBody = "<p>Hello,</p>";
	if(isUsersContractorManager) {
	htmlBody = htmlBody + "<p>You have been identified as the contractor manager of the user this request is for...</p>";
	}
	else if(isUsersTrustedRequester){
	htmlBody = htmlBody + "<p>You have been identified as the trusted requester of the user this request is for...</p>";
	}
	else {	
	htmlBody = htmlBody + "<p>You have been identified as the manager of the user this request is for...</p>";
    }	
	htmlBody=htmlBody + "<p>As a result, related updates will be applied immediately upon your submission of this form.</p><p>If you wish to proceed, select the button labeled \"Approve Request\"; otherwise, select the button labeled \"Reject Request\" to back out.</p><p>Submission of this request doubles as affirmation that you have read and understand <a href=\"https://communities.ascension.org/PoliciesAndProcedures/Email%20Use.pdf\" target=\"_blank\">Ascension Administrative Policy #403</a>.</p><p>Lastly, if this request was opened for an R1 Associate it should be rejected; R1 Associates MUST utilize R1\'s internal email system.</p>";	
	return htmlBody;

} else {

	htmlBody = "<p>Hello,</p><p>A request has been opened to update the listed contractor\'s mailbox license.</p><p>Please approve or reject this request using the labeled buttons on the bottom of the form.</p><p>Approval of this request doubles as affirmation that you have read and understand <a href=\"https://communities.ascension.org/PoliciesAndProcedures/Email%20Use.pdf\" target=\"_blank\">Ascension Administrative Policy #403</a>.</p><p>Lastly, if this request was opened for an R1 Associate it should be rejected; R1 Associates MUST utilize R1\'s internal email system.</p>";
	return htmlBody;
	
}

