import sailpoint.object.Identity;
          import sailpoint.tools.Util;

          if (isUsersManager || isUsersContractorManager) {

          return launcher;

          } else {

          Identity refIdentity = context.getObjectByName(Identity.class, identityName);
          Identity refManager = refIdentity.getManager();

          if (refManager != null) {

          String managerName = refManager.getName();

          return managerName;

          } else {

          return fallbackApprover;

          }

          }

