import sailpoint.object.WorkItem;
import sailpoint.object.WorkItem.State;
import sailpoint.object.IdentityRequest;
import sailpoint.object.IdentityRequestItem;

IdentityRequest identityRequest = context.getObjectByName(IdentityRequest.class, identityRequestId);

List requestItems = identityRequest.getItems();

if (requestItems != null && requestItems.size() > 0) {

   for (IdentityRequestItem requestItem : requestItems) {

       requestItem.setApprovalState(WorkItem.State.Rejected);
       context.saveObject(requestItem);

   }

}

if(State.Finished != identityRequest.getState()){

  identityRequest.setCompletionStatus(IdentityRequest.CompletionStatus.Failure);

  identityRequest.setEndDate(new Date());

  identityRequest.setExecutionStatus(IdentityRequest.ExecutionStatus.Terminated);

  System.out.println("Identity Request State set to: " + identityRequest.getState());

  context.saveObject(identityRequest);

  context.commitTransaction();

}

ConditionScript.Source:
import sailpoint.object.Identity;

boolean isUsersManager = contextIsUsersManager(identityName);
boolean isUsersContractorManager = contextIsUsersContractorManager(identityName);
boolean isUsersTrustedRequester = contextIsTrustedRequester(launcher);
wfcontext.setVariable("isUsersManager", isUsersManager);
wfcontext.setVariable("isUsersContractorManager", isUsersContractorManager);
wfcontext.setVariable("isUsersTrustedRequester", isUsersTrustedRequester);
if (!isUsersManager || !isUsersContractorManager || !isUsersTrustedRequester) { 
   return true;
} else {

  return false;

}

